     1→/**
     2→ * Entire CLI checkpoint indexer.
     3→ *
     4→ * Reads the shard-tree produced by `entire commit` on the `entire/checkpoints/v1`
     5→ * branch and writes Checkpoint / CheckpointSession / CheckpointMessage records
     6→ * into the SQLite database.
     7→ *
     8→ * Directory layout expected under the root:
     9→ *   <root>/<shard2>/<id10>/metadata.json
    10→ *   <root>/<shard2>/<id10>/0/metadata.json
    11→ *   <root>/<shard2>/<id10>/0/full.jsonl
    12→ *   <root>/<shard2>/<id10>/1/metadata.json    (if multiple sessions)
    13→ *   <root>/<shard2>/<id10>/1/full.jsonl
    14→ *   ...
    15→ */
    16→
    17→import { readdirSync, readFileSync, existsSync, statSync } from "fs";
    18→import { join } from "path";
    19→import type { PrismaClient } from "../prisma/generated/client/index.js";
    20→
    21→// ─── Raw shapes from the checkpoint files ─────────────────────────────────────
    22→
    23→interface RootMeta {
    24→  cli_version?: string;
    25→  checkpoint_id?: string;
    26→  strategy?: string;
    27→  branch?: string;
    28→  files_touched?: string[];
    29→  token_usage?: Record<string, unknown>;
    30→}
    31→
    32→interface SummaryLearnings {
    33→  repo?: string[];
    34→  code?: Array<{ path: string; finding: string }>;
    35→  workflow?: string[];
    36→}
    37→
    38→interface SessionSummary {
    39→  intent?: string;
    40→  outcome?: string;
    41→  learnings?: SummaryLearnings;
    42→  friction?: string[];
    43→  open_items?: string[];
    44→}
    45→
    46→interface SessionMeta {
    47→  session_id: string;
    48→  checkpoint_id?: string;
    49→  cli_version?: string;
    50→  strategy?: string;
    51→  created_at?: string;
    52→  branch?: string;
    53→  turn_id?: string;
    54→  agent?: string;
    55→  token_usage?: Record<string, unknown>;
    56→  initial_attribution?: Record<string, unknown>;
    57→  files_touched?: string[];
    58→  summary?: SessionSummary;
    59→  checkpoint_transcript_start?: number;
    60→  transcript_lines_at_start?: number;
    61→}
    62→
    63→// A single line from full.jsonl — fields vary by type
    64→export interface FullJsonlEvent {
    65→  uuid?: string;
    66→  messageId?: string;      // used by "file-history-snapshot" instead of uuid
    67→  sessionId?: string;
    68→  parentUuid?: string;
    69→  type: string;
    70→  timestamp?: string;
    71→  cwd?: string;
    72→  gitBranch?: string;
    73→  slug?: string;
    74→  version?: string;
    75→  planContent?: string;
    76→  toolUseID?: string;
    77→  parentToolUseID?: string;
    78→  isSidechain?: boolean;
    79→  userType?: string;
    80→  message?: unknown;
    81→  data?: unknown;
    82→  [key: string]: unknown;
    83→}
    84→
    85→// ─── Parsing ──────────────────────────────────────────────────────────────────
    86→
    87→/**
    88→ * Parse a full.jsonl string into an array of event objects.
    89→ * Malformed lines are silently skipped.
    90→ */
    91→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    92→  const out: FullJsonlEvent[] = [];
    93→  for (const line of content.split("\n")) {
    94→    const trimmed = line.trim();
    95→    if (!trimmed) continue;
    96→    try {
    97→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
    98→    } catch {
    99→      // skip malformed line
   100→    }
   101→  }
   102→  return out;
   103→}
   104→
   105→/** Return the unique key for an event, preferring uuid then messageId. */
   106→function eventKey(e: FullJsonlEvent): string | null {
   107→  return e.uuid ?? e.messageId ?? null;
   108→}
   109→
   110→// ─── Single-checkpoint indexer ────────────────────────────────────────────────
   111→
   112→/**
   113→ * Index one checkpoint directory (the folder named by the last 10 hex chars,
   114→ * e.g. `<root>/0c/b6cf391c40`).
   115→ *
   116→ * @returns Number of new messages written (already-indexed events are skipped).
   117→ */
   118→export async function indexCheckpoint(
   119→  db: PrismaClient,
   120→  checkpointDir: string,
   121→  checkpointId: string,
   122→): Promise<number> {
   123→  const metaPath = join(checkpointDir, "metadata.json");
   124→  if (!existsSync(metaPath)) {
   125→    throw new Error(`No metadata.json found at ${checkpointDir}`);
   126→  }
   127→
   128→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   129→
   130→  // Upsert root Checkpoint record
   131→  await db.checkpoint.upsert({
   132→    where: { checkpointId },
   133→    create: {
   134→      checkpointId,
   135→      cliVersion: meta.cli_version ?? null,
   136→      branch: meta.branch ?? null,
   137→      strategy: meta.strategy ?? null,
   138→      filesTouched: meta.files_touched ? JSON.stringify(meta.files_touched) : null,
   139→      tokenUsage: meta.token_usage ? JSON.stringify(meta.token_usage) : null,
   140→    },
   141→    update: {
   142→      cliVersion: meta.cli_version ?? null,
   143→      branch: meta.branch ?? null,
   144→      strategy: meta.strategy ?? null,
   145→      filesTouched: meta.files_touched ? JSON.stringify(meta.files_touched) : null,
   146→      tokenUsage: meta.token_usage ? JSON.stringify(meta.token_usage) : null,
   147→    },
   148→  });
   149→
   150→  // Find session sub-directories (0/, 1/, 2/, …)
   151→  const sessionDirs = readdirSync(checkpointDir)
   152→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   153→    .sort((a, b) => parseInt(a) - parseInt(b));
   154→
   155→  let totalNew = 0;
   156→
   157→  for (const sessionDir of sessionDirs) {
   158→    const sessionIndex = parseInt(sessionDir, 10);
   159→    const sessionPath = join(checkpointDir, sessionDir);
   160→    const sessionMetaPath = join(sessionPath, "metadata.json");
   161→    if (!existsSync(sessionMetaPath)) continue;
   162→
   163→    const sessionMeta = JSON.parse(readFileSync(sessionMetaPath, "utf8")) as SessionMeta;
   164→    const { session_id: sessionId } = sessionMeta;
   165→    if (!sessionId) continue;
   166→
   167→    // Upsert CheckpointSession
   168→    const sessionData = {
   169→      checkpointId,
   170→      sessionIndex,
   171→      turnId: sessionMeta.turn_id ?? null,
   172→      agent: sessionMeta.agent ?? null,
   173→      createdAt: sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   174→      filesTouched: sessionMeta.files_touched ? JSON.stringify(sessionMeta.files_touched) : null,
   175→      tokenUsage: sessionMeta.token_usage ? JSON.stringify(sessionMeta.token_usage) : null,
   176→      initialAttribution: sessionMeta.initial_attribution
   177→        ? JSON.stringify(sessionMeta.initial_attribution)
   178→        : null,
   179→      checkpointTranscriptStart: sessionMeta.checkpoint_transcript_start ?? null,
   180→      transcriptLinesAtStart: sessionMeta.transcript_lines_at_start ?? null,
   181→    };
   182→    await db.checkpointSession.upsert({
   183→      where: { sessionId },
   184→      create: { sessionId, ...sessionData },
   185→      update: sessionData,
   186→    });
   187→
   188→    // Record the checkpoint→session link (idempotent)
   189→    await db.checkpointSessionLink.upsert({
   190→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   191→      create: { checkpointId, sessionId },
   192→      update: {},
   193→    });
   194→
   195→    // Upsert CheckpointSummary if present
   196→    if (sessionMeta.summary) {
   197→      const sm = sessionMeta.summary;
   198→      const summaryData = {
   199→        intent: sm.intent ?? "",
   200→        outcome: sm.outcome ?? "",
   201→        learningsRepo: sm.learnings?.repo ? JSON.stringify(sm.learnings.repo) : null,
   202→        learningsCode: sm.learnings?.code ? JSON.stringify(sm.learnings.code) : null,
   203→        learningsWorkflow: sm.learnings?.workflow ? JSON.stringify(sm.learnings.workflow) : null,
   204→        friction: sm.friction ? JSON.stringify(sm.friction) : null,
   205→        openItems: sm.open_items ? JSON.stringify(sm.open_items) : null,
   206→      };
   207→      await db.checkpointSummary.upsert({
   208→        where: { sessionId },
   209→        create: { sessionId, ...summaryData },
   210→        update: summaryData,
   211→      });
   212→    }
   213→
   214→    // Parse and index full.jsonl
   215→    const fullPath = join(sessionPath, "full.jsonl");
   216→    if (!existsSync(fullPath)) continue;
   217→
   218→    const events = parseFullJsonl(readFileSync(fullPath, "utf8"));
   219→
   220→    for (const event of events) {
   221→      const key = eventKey(event);
   222→      if (!key) continue; // can't upsert without a unique key
   223→
   224→      // Skip if already indexed
   225→      const exists = await db.checkpointMessage.findUnique({
   226→        where: { uuid: key },
   227→        select: { id: true },
   228→      });
   229→      if (exists) continue;
   230→
   231→      await db.checkpointMessage.create({
   232→        data: {
   233→          uuid: key,
   234→          sessionId,
   235→          parentUuid: event.parentUuid ?? null,
   236→          type: event.type,
   237→          timestamp: event.timestamp ? new Date(event.timestamp) : null,
   238→          cwd: event.cwd ?? null,
   239→          gitBranch: event.gitBranch ?? null,
   240→          slug: event.slug ?? null,
   241→          version: event.version ?? null,
   242→          planContent: event.planContent ?? null,
   243→          toolUseId: event.toolUseID ?? null,
   244→          parentToolUseId: event.parentToolUseID ?? null,
   245→          data: JSON.stringify(event),
   246→        },
   247→      });
   248→      totalNew++;
   249→    }
   250→  }
   251→
   252→  return totalNew;
   253→}
   254→
   255→// ─── Full-tree indexer ────────────────────────────────────────────────────────
   256→
   257→/**
   258→ * Walk a checkpoints root directory and index every checkpoint found.
   259→ *
   260→ * The root must have the shard structure:
   261→ *   <root>/<2-hex-chars>/<10-hex-chars>/
   262→ *
   263→ * @param onProgress  Optional callback called after each checkpoint.
   264→ */
   265→export async function indexAllCheckpoints(
   266→  db: PrismaClient,
   267→  rootDir: string,
   268→  onProgress?: (checkpointId: string, newMessages: number) => void,
   269→): Promise<{ checkpoints: number; newMessages: number }> {
   270→  let totalCheckpoints = 0;
   271→  let totalNew = 0;
   272→
   273→  const shards = readdirSync(rootDir)
   274→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   275→
   276→  for (const shard of shards) {
   277→    const shardPath = join(rootDir, shard);
   278→    const ids = readdirSync(shardPath)
   279→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   280→
   281→    for (const rest of ids) {
   282→      const checkpointId = shard + rest;
   283→      const checkpointDir = join(shardPath, rest);
   284→      try {
   285→        const n = await indexCheckpoint(db, checkpointDir, checkpointId);
   286→        totalNew += n;
   287→        totalCheckpoints++;
   288→        onProgress?.(checkpointId, n);
   289→      } catch (err) {
   290→        process.stderr.write(`indexer: skipping ${checkpointId}: ${err}\n`);
   291→      }
   292→    }
   293→  }
   294→
   295→  return { checkpoints: totalCheckpoints, newMessages: totalNew };
   296→}
   297→

